Functionality \mathcal{F}_{\text{CGKA}}: Consistency Helpers
helper *consistent-prop(p, id, act, stat)
helper *consistent-comm(c, id, \vec{p}, mem)
// Preexisting p valid for id proposing act?
// Preexisting c valid for id committing \vec{p}?
\mathbf{assert} \ \mathsf{Prop}[p].\mathsf{orig} = \mathsf{id} \land \mathsf{Prop}[p].\mathsf{act} = \mathsf{act}
assert *valid-successor(c, id, \vec{p}, mem)
\land \mathsf{Prop}[p].\mathsf{par} = \mathsf{Ptr}[\mathsf{id}]
assert \operatorname{RndCor}[\operatorname{id}] \neq \operatorname{good} \wedge \operatorname{Node}[c].\operatorname{orig} = \operatorname{id}
helper *valid-successor(c, id, \vec{p}, mem)
helper *attach(c, c', id, \vec{p})
// Preexisting node valid for id processing (c, \vec{p})?
// Attach detached root c' under new name c as successor of id's node.
assert \mathsf{Node}[c] \neq \bot \land \mathsf{Node}[c].\mathsf{mem} = \mathsf{mem}
assert c' \neq \mathsf{root}_0
\land \mathsf{Node}[c].\mathsf{pro} \in \{\bot, \vec{p}\} \land \mathsf{Node}[c].\mathsf{par} \in \{\bot, \mathsf{Ptr}[\mathsf{id}]\}
\mathsf{Node}[c'].\mathsf{par} \leftarrow \mathsf{Ptr}[\mathsf{id}]; \, \mathsf{Node}[c'].\mathsf{pro} \leftarrow \vec{p}; \, \mathsf{Node}[c] \leftarrow \mathsf{Node}[c']; \, \mathsf{Node}[c'] \leftarrow \bot
